// Accepts a single webhook payload that may carry either or both of:
//   { employees: [...] }    \u2192 paystub rows (existing HRIS dispatch payload)
//   { receipts: [...]  }    \u2192 orphanage receipts (visit_wages /
//                              budget_request / gift_payment / tenure_gift)
// Output: one item per row, tagged with `_kind` so the Switch node downstream
// can route to the right email renderer.

const body = (items[0] && items[0].json) || {};
const out = [];

for (const emp of Array.isArray(body.employees) ? body.employees : []) {
  out.push({ json: Object.assign({ _kind: 'paystub' }, emp) });
}
for (const rcpt of Array.isArray(body.receipts) ? body.receipts : []) {
  out.push({ json: Object.assign({ _kind: 'orphanage' }, rcpt) });
}

return out;

// Render the orphanage receipt email as inline HTML, choose recipient + subject.
// One input item per receipt; output adds `to`, `subject`, `html` fields.
//
// Expected per-receipt payload (the wizard should POST these in body.receipts):
//   {
//     kind: 'visit_wages' | 'budget_request' | 'gift_payment' | 'tenure_gift',
//     id: string,
//     month_label: string,                      // e.g. 'May 2026'
//     ... type-specific fields (see each branch).
//   }

const LOGO = 'https://host.simple.biz/email/simplelogo.png';

function fmtPHP(n) {
  if (n == null) return '\u20b1\u00a00.00';
  return '\u20b1' + Number(n).toLocaleString('en-PH', { minimumFractionDigits: 2, maximumFractionDigits: 2 });
}
function fmtRate(n) {
  if (n == null) return '\u2014';
  return Number(n).toLocaleString('en-PH', { minimumFractionDigits: 2, maximumFractionDigits: 2 });
}
function fmtUSD(n) {
  if (n == null) return '$0.00';
  return '$' + Number(n).toLocaleString('en-US', { minimumFractionDigits: 2, maximumFractionDigits: 2 });
}
function fmtLongDate(raw) {
  if (!raw) return '\u2014';
  const s = String(raw).trim();
  if (!s) return '\u2014';
  const isoOnly = s.length >= 10 ? s.slice(0, 10) : s;
  const d = new Date(isoOnly + 'T00:00:00');
  if (Number.isNaN(d.getTime())) return s;
  return d.toLocaleDateString('en-US', { year: 'numeric', month: 'long', day: 'numeric' });
}
function esc(v) {
  if (v == null) return '';
  return String(v)
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;');
}

const WATERMARK_STYLE = '<style>\n  .paystub-body { position: relative; }\n  .paystub-body::before {\n    content: "";\n    position: absolute;\n    top: 110px; left: 0; right: 0; bottom: 70px;\n    overflow: hidden;\n    background-image:\n      url("' + LOGO + '"), url("' + LOGO + '"), url("' + LOGO + '"), url("' + LOGO + '"),\n      url("' + LOGO + '"), url("' + LOGO + '"), url("' + LOGO + '"), url("' + LOGO + '"),\n      url("' + LOGO + '"), url("' + LOGO + '"), url("' + LOGO + '"), url("' + LOGO + '");\n    background-repeat: no-repeat;\n    background-size: 120px, 120px, 120px, 120px, 70px, 70px, 70px, 70px, 40px, 40px, 40px, 40px;\n    background-position: 10% 8%, 75% 22%, 25% 55%, 85% 78%, 50% 12%, 12% 38%, 65% 48%, 38% 85%, 90% 10%, 5% 72%, 55% 30%, 92% 55%;\n    transform: rotate(-28deg);\n    opacity: 0.08;\n    pointer-events: none;\n    z-index: 2;\n  }\n</style>';

function header(eyebrow, greeting, subline) {
  return ''
    + '<td style="background:linear-gradient(to top right,#4338ca 0%,#ffffff 50%,#f97316 100%);padding:24px 28px;text-align:center;">'
    + '<div style="color:#1e293b;font-size:11px;letter-spacing:0.15em;font-weight:700;text-transform:uppercase;">' + eyebrow + '</div>'
    + '<div style="margin-top:8px;color:#0f172a;font-size:20px;font-weight:700;letter-spacing:-0.01em;">' + greeting + '</div>'
    + '<div style="margin-top:4px;color:#334155;font-size:12px;">' + subline + '</div>'
    + '</td>';
}

function sectionHeading(label, color) {
  const c = color || '#ea580c';
  return ''
    + '<tr><td style="padding:16px 24px 4px 24px;">'
    + '<div style="font-size:11px;letter-spacing:0.12em;font-weight:700;color:' + c + ';text-transform:uppercase;">' + label + '</div>'
    + '<div style="height:3px;background:linear-gradient(to top right,#4338ca 0%,#ffffff 50%,#f97316 100%);border-radius:2px;margin-top:6px;width:60px;"></div>'
    + '</td></tr>';
}

function sectionCard(rowsHTML) {
  return ''
    + '<tr><td style="padding:8px 24px 0 24px;">'
    + '<table role="presentation" cellpadding="0" cellspacing="0" border="0" width="100%" style="background:linear-gradient(to top right,#eff6ff 0%,#ffffff 50%,#fffaf3 100%);border:1px solid #fde4cb;border-radius:8px;">'
    + '<tr><td style="padding:12px 16px;">'
    + '<table role="presentation" cellpadding="0" cellspacing="0" border="0" width="100%">' + rowsHTML + '</table>'
    + '</td></tr></table>'
    + '</td></tr>';
}

function labelRow(label, value, opts) {
  const labelWidth = (opts && opts.labelWidth) || 110;
  const valueColor = (opts && opts.valueColor) || '#111827';
  const valueWeight = (opts && opts.valueWeight) || 600;
  return ''
    + '<tr>'
    + '<td style="font-size:12px;color:#9a6b3f;padding:3px 0;width:' + labelWidth + 'px;">' + label + '</td>'
    + '<td style="font-size:13px;color:' + valueColor + ';font-weight:' + valueWeight + ';padding:3px 0;">' + value + '</td>'
    + '</tr>';
}

function amountRow(label, amount, color) {
  const c = color || '#2563eb';
  return ''
    + '<tr>'
    + '<td style="font-size:12px;color:#9a6b3f;padding:3px 0;">' + label + '</td>'
    + '<td align="right" style="font-size:13px;color:' + c + ';font-weight:700;padding:3px 0;">' + amount + '</td>'
    + '</tr>';
}

function totalBar(label, amount, currency) {
  return ''
    + '<tr><td style="padding:16px 24px 8px 24px;">'
    + '<table role="presentation" cellpadding="0" cellspacing="0" border="0" width="100%" style="background:linear-gradient(to top right,#3730a3 0%,#ffffff 50%,#ea580c 100%);border-radius:10px;">'
    + '<tr><td style="padding:16px 20px;">'
    + '<table role="presentation" cellpadding="0" cellspacing="0" border="0" width="100%"><tr>'
    + '<td style="color:#1e293b;font-size:11px;letter-spacing:0.12em;text-transform:uppercase;font-weight:700;">' + label + '</td>'
    + '<td align="right" style="color:#0f172a;font-size:22px;font-weight:800;letter-spacing:-0.01em;">' + amount + ' <span style="font-size:12px;font-weight:600;color:#475569;">' + currency + '</span></td>'
    + '</tr></table>'
    + '</td></tr></table>'
    + '</td></tr>';
}

const FOOTER = ''
  + '<tr><td style="background:linear-gradient(to top right,#eff6ff 0%,#ffffff 50%,#fffaf3 100%);padding:14px 24px;">'
  + '<table role="presentation" cellpadding="0" cellspacing="0" border="0" width="100%"><tr>'
  + '<td style="vertical-align:middle;width:50px;"><img src="' + LOGO + '" alt="Simple" width="42" style="display:block;height:auto;width:42px;border:0;" /></td>'
  + '<td style="vertical-align:middle;padding-left:12px;text-align:right;">'
  + '<div style="font-size:12px;color:#1e293b;font-weight:700;">Simple \u00b7 Confidential</div>'
  + '<div style="font-size:10px;color:#94a3b8;">Automated dispatch from Simple HRIS</div>'
  + '</td></tr></table>'
  + '</td></tr>';

function wrap(headerHTML, sectionsHTML) {
  return ''
    + '<!DOCTYPE html><html><head><meta charset="utf-8" /><title>Orphanage Receipt</title>' + WATERMARK_STYLE + '</head><body>'
    + '<table role="presentation" cellpadding="0" cellspacing="0" border="0" width="100%" style="background:linear-gradient(to top right,#c7d2fe 0%,#ffffff 50%,#ffedd5 100%);padding:24px 16px;font-family:-apple-system,BlinkMacSystemFont,\'Segoe UI\',Roboto,Helvetica,Arial,sans-serif;color:#1f2937;">'
    + '<tr><td align="center">'
    + '<table role="presentation" cellpadding="0" cellspacing="0" border="0" width="480" class="paystub-body" style="max-width:480px;background:#ffffff;border-radius:12px;overflow:hidden;box-shadow:0 4px 20px rgba(59,130,246,0.15);position:relative;">'
    + '<tr>' + headerHTML + '</tr>'
    + sectionsHTML
    + FOOTER
    + '</table></td></tr></table></body></html>';
}

const out = [];

for (const item of items) {
  const r = item.json;
  const kind = r.kind;
  const monthLabel = esc(r.month_label || '\u2014');
  let to = '';
  let subject = '';
  let headerHTML = '';
  let sectionsHTML = '';

  if (kind === 'visit_wages') {
    to = r.work_email;
    subject = '[Simple HRIS] Orphanage visit wages \u00b7 ' + monthLabel;

    const eyebrow = 'Simple HRIS \u00b7 Orphanage Visit Receipt \u00b7 ' + monthLabel;
    const greeting = 'Hi ' + esc(r.name || '\u2014') + ',';
    const visitCount = Number(r.visit_count || 0);
    const totalHours = Number(r.total_hours || 0);
    const subline = visitCount + ' approved visit' + (visitCount === 1 ? '' : 's') + ' \u00b7 <strong>' + totalHours.toFixed(1) + 'h</strong> credited';
    headerHTML = header(eyebrow, greeting, subline);

    sectionsHTML += sectionHeading('Recipient');
    sectionsHTML += sectionCard(''
      + labelRow('Name', esc(r.name || '\u2014'))
      + labelRow('Work Email', esc(r.work_email || '\u2014'))
      + labelRow('PAB Period', monthLabel));

    sectionsHTML += sectionHeading('Approved Visits');
    let visitRows = '';
    const visits = Array.isArray(r.visits) ? r.visits : [];
    if (visits.length === 0) {
      visitRows = '<tr><td style="font-size:12px;color:#9a6b3f;padding:3px 0;font-style:italic;">No approved visits.</td></tr>';
    } else {
      for (const v of visits) {
        visitRows += amountRow(esc(fmtLongDate(v.date)), Number(v.hours || 0).toFixed(1) + 'h \u00d7 \u20b1' + fmtRate(r.regular_rate));
      }
    }
    sectionsHTML += sectionCard(visitRows);

    sectionsHTML += sectionHeading('Wage Breakdown', '#7c3aed');
    sectionsHTML += sectionCard(''
      + labelRow('Visits', String(visitCount), { labelWidth: 150 })
      + labelRow('Total Hours', totalHours.toFixed(1) + 'h', { labelWidth: 150 })
      + labelRow('Regular Rate', r.regular_rate != null ? '\u20b1' + fmtRate(r.regular_rate) + ' / h' : '\u2014', { labelWidth: 150 }));

    sectionsHTML += totalBar('Total Wages', fmtPHP(r.wages), 'PHP');
  } else if (kind === 'budget_request') {
    to = r.submitter_email;
    subject = '[Simple HRIS] Orphanage budget approved \u00b7 ' + monthLabel;

    const eyebrow = 'Simple HRIS \u00b7 Orphanage Budget Receipt \u00b7 ' + monthLabel;
    const greeting = 'Hi ' + esc(r.submitter_email || '\u2014') + ',';
    const subline = esc(r.visit_type || '\u2014') + (r.mission_trip ? ' \u00b7 mission trip' : '');
    headerHTML = header(eyebrow, greeting, subline);

    sectionsHTML += sectionHeading('Submitter');
    let infoRows = ''
      + labelRow('Email', esc(r.submitter_email || '\u2014'), { labelWidth: 130 })
      + labelRow('Visit Type', esc(r.visit_type || '\u2014') + (r.mission_trip ? ' (mission trip)' : ''), { labelWidth: 130 })
      + labelRow('Submitted', esc(fmtLongDate(r.submitted_at)), { labelWidth: 130 });
    if (r.decided_at) {
      infoRows += labelRow('Approved', esc(fmtLongDate(r.decided_at)) + (r.decided_by ? ' \u00b7 ' + esc(r.decided_by) : ''), { labelWidth: 130 });
    }
    sectionsHTML += sectionCard(infoRows);

    sectionsHTML += sectionHeading('Budget Breakdown', '#7c3aed');
    sectionsHTML += sectionCard(''
      + amountRow('Subtotal', fmtPHP(r.subtotal))
      + amountRow('Leftover Carry-in', fmtPHP(r.leftover)));

    sectionsHTML += totalBar('Final Amount', fmtPHP(r.final_amount), 'PHP');
  } else if (kind === 'gift_payment') {
    to = r.vendor_email;
    subject = '[Simple HRIS] Orphanage gift payment receipt';

    const eyebrow = 'Simple HRIS \u00b7 Orphanage Gift Payment Receipt \u00b7 ' + monthLabel;
    const greeting = 'Hi ' + esc(r.vendor_name || 'Vendor') + ',';
    const subline = 'Batch: <strong>' + esc(r.batch_label || '\u2014') + '</strong>';
    headerHTML = header(eyebrow, greeting, subline);

    sectionsHTML += sectionHeading('Vendor');
    let vendorRows = ''
      + labelRow('Name', esc(r.vendor_name || '\u2014'))
      + labelRow('Period', esc(r.period_label || '\u2014'))
      + labelRow('Batch', esc(r.batch_label || '\u2014'))
      + labelRow('Status', esc(r.status || '\u2014'));
    if (r.date_sent) {
      vendorRows += labelRow('Date Sent', esc(fmtLongDate(r.date_sent)));
    }
    sectionsHTML += sectionCard(vendorRows);

    sectionsHTML += sectionHeading('Conversion', '#7c3aed');
    sectionsHTML += sectionCard(''
      + amountRow('Amount (USD)', fmtUSD(r.total_usd))
      + labelRow('USD \u2192 PHP rate', '\u20b1' + fmtRate(r.usd_to_php_rate), { labelWidth: 150 }));

    sectionsHTML += totalBar('Total Paid', fmtPHP(r.total_php), 'PHP');
  } else if (kind === 'tenure_gift') {
    to = r.personal_email;
    subject = '[Simple HRIS] Tenure gift approved \u00b7 milestone #' + (r.milestone_index || '');

    const eyebrow = 'Simple HRIS \u00b7 Orphanage Tenure Gift Receipt \u00b7 ' + monthLabel;
    const greeting = 'Hi ' + esc(r.personal_email || '\u2014') + ',';
    const subline = 'Milestone <strong>#' + esc(r.milestone_index) + '</strong> \u00b7 ' + esc(fmtLongDate(r.milestone_date));
    headerHTML = header(eyebrow, greeting, subline);

    sectionsHTML += sectionHeading('Recipient');
    sectionsHTML += sectionCard(''
      + labelRow('Personal Email', esc(r.personal_email || '\u2014'), { labelWidth: 130 })
      + labelRow('Milestone', '#' + esc(r.milestone_index), { labelWidth: 130 })
      + labelRow('Milestone Date', esc(fmtLongDate(r.milestone_date)), { labelWidth: 130 })
      + labelRow('Approved', esc(fmtLongDate(r.decided_at)) + (r.decided_by ? ' \u00b7 ' + esc(r.decided_by) : ''), { labelWidth: 130 }));

    sectionsHTML += sectionHeading('Gift', '#7c3aed');
    sectionsHTML += sectionCard(amountRow(esc(r.gift_name || ('Milestone #' + r.milestone_index + ' gift')), fmtPHP(r.gift_price_php)));

    sectionsHTML += totalBar('Gift Value', fmtPHP(r.gift_price_php), 'PHP');
  } else {
    throw new Error('Unknown orphanage receipt kind: ' + kind);
  }

  if (!to) {
    throw new Error('Missing recipient email for receipt id=' + r.id + ' kind=' + kind);
  }

  out.push({
    json: Object.assign({}, r, {
      to: to,
      subject: subject,
      html: wrap(headerHTML, sectionsHTML),
    }),
  });
}

return out;
